import sqlite3

def products_by_cat(conn: sqlite3.Connection, cat_id: int):
    cur = conn.execute("SELECT * FROM products WHERE category_id = ?", (cat_id,))
    return cur.fetchall()

def search(cur, term):
    q = "SELECT * FROM products WHERE name LIKE '%{}%'".format(term)
    cur.execute(q)
    return cur.fetchall()

def audit_query(cur, uid):
    parts = ["SELECT * FROM audit_log WHERE user_id = ", str(uid)]
    cur.execute("".join(parts))
    return cur.fetchall()

def filter_customers(cur, filters: dict):
    frag = " AND ".join(f"{k} = '{v}'" for k, v in filters.items())
    cur.execute("SELECT * FROM customers WHERE " + frag)
    return cur.fetchall()

